import numpy as np
def metrics(trades,equity_curve=None):
 p=[float(t['pnl']) for t in trades if t.get('pnl') is not None];gross_win=sum(x for x in p if x>0);gross_loss=abs(sum(x for x in p if x<0));curve=equity_curve or [];drawdown=min((float(row.get('drawdown',0)) for row in curve),default=0.);returns=[float(row.get('daily_pnl',0))/max(float(row.get('equity',1)),1) for row in curve];downside=[x for x in returns if x<0];return_std=float(np.std(returns,ddof=1)) if len(returns)>1 else 0.;downside_std=float(np.std(downside,ddof=1)) if len(downside)>1 else 0.
 return {'closed_trades':len(p),'win_rate':float(np.mean([x>0 for x in p])) if p else 0.,'avg_trade_pnl':float(np.mean(p)) if p else 0.,'profit_factor':float(gross_win/gross_loss) if gross_loss else (float('inf') if gross_win else None),'max_drawdown':drawdown,'sharpe':float(np.mean(returns)/max(return_std,1e-9)*np.sqrt(252)) if returns else 0.0,'sortino':float(np.mean(returns)/max(downside_std,1e-9)*np.sqrt(252)) if returns else 0.0,'gross_profit':gross_win,'gross_loss':gross_loss}
